!-- Statistics Cards Section -->
<div class="stats-grid">
  <!-- Stores Card -->
  <div class="stat-card stat-stores">
    <div class="stat-icon">
      <i class="fas fa-store" aria-hidden="true"></i>
    </div>
    <div class="stat-content">
      <h3 data-i18n="stat_stores">Tiendas</h3>
      <p class="stat-number">{{ stats.stores }}</p>
    </div>
  </div>

  <!-- Products Card -->
  <div class="stat-card stat-products">
    <div class="stat-icon">
      <i class="fas fa-box-open" aria-hidden="true"></i>
    </div>
    <div class="stat-content">
      <h3 data-i18n="stat_products">Productos</h3>
      <p class="stat-number">{{ stats.products }}</p>
    </div>
  </div>

  <!-- Employees Card -->
  <div class="stat-card stat-employees">
    <div class="stat-icon">
      <i class="fas fa-users" aria-hidden="true"></i>
    </div>
    <div class="stat-content">
      <h3 data-i18n="stat_employees">Empleados</h3>
      <p class="stat-number">{{ stats.employees }}</p>
    </div>
  </div>

  <!-- Inventory Items Card -->
  <div class="stat-card stat-inventory">
    <div class="stat-icon">
      <i class="fas fa-cubes" aria-hidden="true"></i>
    </div>
    <div class="stat-content">
      <h3 data-i18n="stat_inventory_items">Ítems Inventario</h3>
      <p class="stat-number">{{ stats.inventory_items }}</p>
    </div>
  </div>
</div>

<!-- System Health Card -->
<div class="card">
  <h2><i class="fas fa-heartbeat" aria-hidden="true"></i> <span data-i18n="stat_system_health">Estado del Sistema</span></h2>
  <div id="orion-status" class="status">
    <span data-i18n="page_home_orion_status">Comprobando Orion Context Broker…</span>
  </div>
</div>

<!-- UML Entity Relationship Diagram -->
<div class="card">
  <h2><i class="fas fa-project-diagram" aria-hidden="true"></i> <span data-i18n="stat_uml_diagram">Diagrama UML - Modelo de Datos</span></h2>
  <div id="mermaid-diagram" class="mermaid-container">
    {{ uml_diagram }}
  </div>
</div>

{% endblock %}

{% block extra_head %}
<!-- Mermaid for UML diagrams -->
<script src="https://cdn.jsdelivr.net/npm/mermaid@10/dist/mermaid.min.js"></script>
<script>
  mermaid.initialize({
    startOnLoad: true,
    theme: 'default',
    securityLevel: 'loose'
  });
</script>
{% endblock %}

{% block extra_scripts %}
<script>
  (function () {
    'use strict';

    // Update Mermaid theme when document theme changes
    function updateMermaidTheme() {
      var theme = document.documentElement.getAttribute('data-theme');
      mermaid.initialize({
        theme: theme === 'dark' ? 'dark' : 'default',
        securityLevel: 'loose'
      });
      // Re-render all mermaid diagrams
      document.querySelectorAll('.mermaid').forEach(function(el) {
        el.removeAttribute('data-processed');
      });
      mermaid.contentLoaded();
    }

    // Listen for theme changes
    var themeToggleBtn = document.getElementById('btn-theme-toggle');
    if (themeToggleBtn) {
      themeToggleBtn.addEventListener('click', function() {
        setTimeout(updateMermaidTheme, 100);
      });
    }

    // Check health on page load
    async function checkHealth() {
      var el = document.getElementById('orion-status');
      try {
        var r = await fetch('/health');
        var d = await r.json();
        if (d.status === 'ok') {
          el.className = 'status ok';
          el.innerHTML = '<i class="fas fa-check-circle" aria-hidden="true"></i> '
                       + window.i18n.t('page_home_orion_ok');
        } else {
          el.className = 'status error';
          el.innerHTML = '<i class="fas fa-exclamation-triangle" aria-hidden="true"></i> '
                       + window.i18n.t('page_home_orion_error');
        }
      } catch (e) {
        el.className = 'status error';
        el.innerHTML = '<i class="fas fa-times-circle" aria-hidden="true"></i> '
                     + window.i18n.t('page_home_backend_error');
      }
    }

    // Wait for i18n to finish loading before calling health check
    document.addEventListener('DOMContentLoaded', function() {
      checkHealth();
      // Also render mermaid after DOM is loaded
      mermaid.contentLoaded();
    }

/* ============================================================
   Statistics Cards Grid
   ============================================================ */

.stats-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
}

.stat-card {
  display: flex;
  align-items: center;
  padding: 1.5rem;
  border-radius: 10px;
  box-shadow: var(--card-shadow);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  cursor: pointer;
}

.stat-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 8px 16px var(--shadow);
}

.stat-icon {
  font-size: 2.5rem;
  margin-right: 1.5rem;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 80px;
  height: 80px;
  border-radius: 8px;
}

.stat-content h3 {
  margin: 0 0 0.5rem;
  font-size: 0.95rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  opacity: 0.85;
}

.stat-number {
  margin: 0;
  font-size: 2rem;
  font-weight: 700;
}

/* Color schemes for each stat card */
.stat-stores {
  background: linear-gradient(135deg, #FF6B6B 0%, #FF8E8E 100%);
  color: #ffffff;
}

.stat-stores .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-products {
  background: linear-gradient(135deg, #4ECDC4 0%, #6FE0DD 100%);
  color: #ffffff;
}

.stat-products .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

.stat-employees {
  background: linear-gradient(135deg, #95E1D3 0%, #B5EFE1 100%);
  color: #1a1a2e;
}

.stat-employees .stat-icon {
  background-color: rgba(26, 26, 46, 0.1);
  color: #1a1a2e;
}

.stat-inventory {
  background: linear-gradient(135deg, #F38181 0%, #F5A6A6 100%);
  color: #ffffff;
}

.stat-inventory .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

/* Dark theme adjustments for stat cards */
:root[data-theme="dark"] .stat-stores {
  background: linear-gradient(135deg, #c94545 0%, #d95959 100%);
}

:root[data-theme="dark"] .stat-products {
  background: linear-gradient(135deg, #3a9b95 0%, #4db5ac 100%);
}

:root[data-theme="dark"] .stat-employees {
  background: linear-gradient(135deg, #6fb8a6 0%, #86cbb5 100%);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-employees .stat-icon {
  background-color: rgba(255, 255, 255, 0.2);
  color: #ffffff;
}

:root[data-theme="dark"] .stat-inventory {
  background: linear-gradient(135deg, #c96668 0%, #d97d7e 100%);
}

/* ============================================================
   Mermaid Diagram Container
   ============================================================ */

.mermaid-container {
  display: flex;
  justify-content: center;
  padding: 1.5rem;
  overflow-x: auto;
  background-color: var(--bg-alt);
  border-radius: 8px;
  border: 1px solid var(--border);
}

.mermaid {
  display: flex;
  justify-content: center;
}

